以下是使用C++语言在VS2022中编写的找出水仙花数的代码：

```c++
#include <iostream>
#include <cmath>
using namespace std;

bool isArmstrongNumber(int number) {
    int numDigits = to_string(number).length();
    int sum = 0;
    int temp = number;

    while (temp > 0) {
        int digit = temp % 10;
        sum += pow(digit, numDigits);
        temp /= 10;
    }

    if (number == sum) {
        return true;
    }
    else {
        return false;
    }
}

int main() {
    int lowerLimit, upperLimit;

    cout << "Enter the lower limit: ";
    cin >> lowerLimit;
    cout << "Enter the upper limit: ";
    cin >> upperLimit;

    cout << "Armstrong numbers between " << lowerLimit << " and " << upperLimit << " are: ";
    for (int i = lowerLimit; i <= upperLimit; i++) {
        if (isArmstrongNumber(i)) {
            cout << i << " ";
        }
    }

    return 0;
}
```

这段代码首先定义了一个函数`isArmstrongNumber()`，用于判断一个给定的数是否为水仙花数。然后在`main()`函数中，用户输入了一个下界和一个上界，然后使用循环从下界遍历到上界，找出所有的水仙花数并输出。

请注意，水仙花数是指一个 n 位数（n≥3），它的每个位上的数字的 n 次幂之和等于它本身。例如，153是一个水仙花数，因为1³ + 5³ + 3³ = 153。

对不起，我之前的回答有误。在C++中，`to_string()`是一个将数字转换为字符串的函数，在 C++11 中引入的。然而，在某些编译环境中可能不支持。为了避免该问题，您可以使用以下方法来计算数字的位数：

```c++
int numDigits = 0;
int temp = number;

while (temp > 0) {
    numDigits++;
    temp /= 10;
}
```

这将计算给定数字的位数。

根据此更正，以下是更新后的代码：

```c++
#include <iostream>
#include <cmath>
using namespace std;

bool isArmstrongNumber(int number) {
    int numDigits = 0;
    int temp = number;

    while (temp > 0) {
        numDigits++;
        temp /= 10;
    }

    int sum = 0;
    temp = number;

    while (temp > 0) {
        int digit = temp % 10;
        sum += pow(digit, numDigits);
        temp /= 10;
    }

    if (number == sum) {
        return true;
    }
    else {
        return false;
    }
}

int main() {
    int lowerLimit, upperLimit;

    cout << "Enter the lower limit: ";
    cin >> lowerLimit;
    cout << "Enter the upper limit: ";
    cin >> upperLimit;

    cout << "Armstrong numbers between " << lowerLimit << " and " << upperLimit << " are: ";
    for (int i = lowerLimit; i <= upperLimit; i++) {
        if (isArmstrongNumber(i)) {
            cout << i << " ";
        }
    }

    return 0;
}
```

